                {pronoun:"ich",form:"esse",src:"I eat"},
                {pronoun:"du",form:"isst",src:"you eat"},
                {pronoun:"er/sie/es",form:"isst",src:"he/she/it eats"},
                {pronoun:"wir",form:"essen",src:"we eat"},
                {pronoun:"ihr",form:"esst",src:"you all eat"},
                {pronoun:"sie/Sie",form:"essen",src:"they/you (formal) eat"}
